part of 'post_list_bloc.dart';
class PostListState extends Equatable { final PostListStatus status; final List<PostEntity> posts; final bool hasReachedMax; final Failure? error; const PostListState({this.status=PostListStatus.initial, this.posts=const [], this.hasReachedMax=false, this.error}); bool get isInitialLoading=>status==PostListStatus.initial||status==PostListStatus.loading; bool get hasFailure=>status==PostListStatus.failure; PostListState copyWith({PostListStatus? status, List<PostEntity>? posts, bool? hasReachedMax, Failure? error, bool clearError=false})=>PostListState(status:status??this.status, posts:posts??this.posts, hasReachedMax:hasReachedMax??this.hasReachedMax, error:clearError?null:error??this.error); @override List<Object?> get props=>[status,posts,hasReachedMax,error]; }
